// ============================ CELESTIAL 天界星壇 — ground decals + standing decor ============================
// Low-contrast ground decals (etched star scratches / pale dust / faint cloud threads) that read as
// texture on the celestial floor (base '#5a6fae' / '#6a80c4'), plus a handful of standing props
// (floating rune stone, broken pillar stump, luminous lichen stone, arch fragment) in the existing
// white-gold-astral "holy sanctum" palette. No p.outline on decals; standing decor keeps the usual
// softShadow + rimLight + outline(P.ink) finish used by bd_cel_*.

// local floor-family anchors (matches biomes.js `celestial` floor/floor2/line — kept literal here
// since those hexes live inline in biomes.js, not in palette.js P)
const CEL_FLOOR = '#5a6fae';
const CEL_FLOOR2 = '#6a80c4';

// ---------------------------------------------------------------------------------------------
// (a) GROUND DECALS — decal_celestial_* — low contrast, no outline, at most 2 with a soft glow.
// ---------------------------------------------------------------------------------------------

defineSprite('decal_celestial_starnick', 10, 6, (p) => {   // small etched 4-point star scratch
  const base = darken(CEL_FLOOR, 0.12);
  p.line(5, 1, 5, 5, base);
  p.line(2, 3, 8, 3, base);
  p.px(5, 3, lighten(CEL_FLOOR, 0.1));
  p.px(3, 2, darken(CEL_FLOOR, 0.16));
  p.px(7, 4, darken(CEL_FLOOR, 0.16));
}, { anchor: 'center' });

defineSprite('decal_celestial_starnick2', 8, 6, (p) => {   // smaller angled star scratch
  const base = darken(CEL_FLOOR2, 0.14);
  p.line(4, 1, 4, 4, base);
  p.line(1, 3, 7, 2, darken(CEL_FLOOR2, 0.1));
  p.px(4, 2, lighten(CEL_FLOOR2, 0.1));
}, { anchor: 'center' });

defineSprite('decal_celestial_dustwisp', 12, 5, (p) => {   // pale drifted-dust patch
  const dust = lighten(CEL_FLOOR2, 0.14);
  p.ellipse(6, 2, 5, 2, withAlpha(dust, 0.18));
  p.ellipse(4, 2, 3, 1.4, withAlpha(lighten(CEL_FLOOR2, 0.17), 0.16));
  p.speckle(1, 0, 10, 5, withAlpha(dust, 0.14), 4, 21);
}, { anchor: 'center' });

defineSprite('decal_celestial_dustwisp2', 10, 4, (p) => {  // smaller dust patch, tighter cluster
  const dust = lighten(CEL_FLOOR, 0.15);
  p.ellipse(5, 2, 4, 1.6, withAlpha(dust, 0.16));
  p.speckle(1, 0, 8, 4, withAlpha(lighten(CEL_FLOOR, 0.12), 0.12), 3, 57);
}, { anchor: 'center' });

defineSprite('decal_celestial_cloudstreak', 14, 6, (p) => { // faint drifting cloud-thread mark
  const wisp = lighten(CEL_FLOOR2, 0.16);
  p.line(1, 4, 7, 2, withAlpha(wisp, 0.22));
  p.line(4, 5, 12, 2, withAlpha(lighten(CEL_FLOOR, 0.14), 0.16));
  p.px(9, 2, withAlpha(wisp, 0.26));
}, { anchor: 'center' });

defineSprite('decal_celestial_cloudstreak2', 12, 5, (p) => { // shorter cloud-thread variant
  const wisp = lighten(CEL_FLOOR, 0.15);
  p.line(1, 3, 10, 1, withAlpha(wisp, 0.18));
  p.px(6, 2, withAlpha(lighten(CEL_FLOOR2, 0.18), 0.22));
}, { anchor: 'center' });

defineSprite('decal_celestial_marblecrack', 10, 8, (p) => { // thin marble crack
  const crack = darken(CEL_FLOOR, 0.18);
  p.line(2, 1, 5, 4, crack);
  p.line(5, 4, 4, 7, crack);
  p.line(5, 4, 8, 5, darken(CEL_FLOOR, 0.12));
  p.px(2, 1, lighten(CEL_FLOOR, 0.1));
}, { anchor: 'center' });

defineSprite('decal_celestial_glimmer', 8, 6, (p) => {      // MICROGLOW #1 — soft holy patch, small
  p.ellipse(4, 3, 3, 2, lighten(CEL_FLOOR2, 0.1));
  p.ellipse(4, 3, 2, 1.3, lighten(CEL_FLOOR2, 0.16));
  p.glow(4, 3, 2, P.holy, 0.14, 3);
  p.px(4, 3, withAlpha(P.holyL, 0.25));
}, { anchor: 'center' });

defineSprite('decal_celestial_stardust', 10, 6, (p) => {    // MICROGLOW #2 — faint star-dust glints
  p.ellipse(5, 3, 4, 2, darken(CEL_FLOOR, 0.1));
  p.ellipse(6, 2, 2, 1.2, lighten(CEL_FLOOR2, 0.12));
  p.px(3, 3, withAlpha(P.star, 0.28));
  p.px(6, 2, withAlpha(P.astralL, 0.2));
  p.px(7, 4, withAlpha(P.holyL, 0.22));
}, { anchor: 'center' });

// ---------------------------------------------------------------------------------------------
// (b) STANDING DECOR — bdx_celestial_* — same finish convention as bd_cel_* (softShadow +
// rimLight + outline(P.ink)); white-gold-astral "holy sanctum" palette throughout.
// ---------------------------------------------------------------------------------------------

defineAnim('bdx_celestial_runestone', 14, 22, 4, (p, f) => { // floating rune slab, gentle bob
  const lift = [0, -1, -1, 0][f];
  p.softShadow(7, 21, 6, 1.6, 0.32);                          // shadow stays grounded even mid-float
  const y = 5 + lift;
  p.rect(3, y, 8, 12, P.cloud);
  p.rect(3, y, 2, 12, P.white);
  p.rect(9, y, 2, 12, mix(P.cloud, P.sky, 0.25));
  p.rect(3, y, 8, 2, lighten(P.cloud, 0.1));
  p.rect(3, y + 10, 8, 2, mix(P.cloud, P.sky, 0.2));
  const pulse = [0.32, 0.42, 0.42, 0.32][f];
  p.glow(7, y + 6, 3, P.holy, pulse, 3);
  p.vline(y + 2, y + 10, 7, P.gold);
  p.hline(5, 9, y + 6, P.gold);
  p.px(7, y + 6, P.holyL);
  p.star4(7, y + 2, 2, P.goldL, P.white);
  p.rimLight(P.rim, 0.4);
  p.outline(P.ink);
}, { anchor: 'feet', fps: 3 });

defineSprite('bdx_celestial_pillarstump', 14, 16, (p) => {   // broken temple-pillar stump
  p.softShadow(7, 15, 6, 1.8, 0.38);
  p.rect(2, 12, 10, 3, P.cloud); p.rect(2, 12, 10, 1, P.white);          // base plinth
  p.rect(4, 2, 6, 10, P.cloud); p.rect(4, 2, 2, 10, P.white); p.rect(9, 2, 1, 10, mix(P.cloud, P.skyL, 0.4));
  p.vline(3, 8, 6, mix(P.cloud, P.sky, 0.2));
  // snapped, jagged top (mid-shaft break, not a clean capital)
  p.line(4, 2, 6, 0, P.cloud); p.line(6, 0, 8, 1, P.cloud); p.line(8, 1, 10, 2, darken(P.cloud, 0.1));
  p.px(6, 0, P.white); p.px(9, 1, darken(P.cloud, 0.15));
  p.hline(4, 9, 4, withAlpha(P.holy, 0.5));                                // weathered gilt inlay band
  p.glow(7, 3, 2, P.holy, 0.22, 2);
  p.rimLight(P.rim, 0.42);
  p.outline(P.ink);
}, { anchor: 'feet' });

defineSprite('bdx_celestial_mossstone', 16, 10, (p) => {     // luminous lichen-crusted stone (光苔石)
  p.softShadow(8, 9, 6, 1.4, 0.36);
  p.ellipse(6, 6, 5, 3, P.cloud); p.ellipse(11, 7, 4, 2.4, mix(P.cloud, P.sky, 0.15)); p.ellipse(8, 4, 3.4, 2.4, lighten(P.cloud, 0.08));
  p.px(4, 4, P.white); p.px(9, 3, P.hiSky);
  // pale holy-toned lichen patches (kept off green/teal so it never reads as a pickup glow)
  p.ellipse(5, 5, 2, 1.2, withAlpha(P.holy, 0.55)); p.ellipse(11, 6, 1.6, 1, withAlpha(P.goldL, 0.5));
  p.px(5, 5, P.holyL); p.px(11, 6, P.gold);
  p.glow(8, 5, 3, P.holy, 0.18, 2);
  p.speckle(3, 3, 10, 5, mix(P.cloud, P.sky, 0.3), 4, 63);
  p.rimLight(P.rim, 0.38);
  p.outline(mix(P.sky, P.ink, 0.5));
}, { anchor: 'feet' });

defineSprite('bdx_celestial_archfragment', 20, 18, (p) => {  // broken stone arch fragment, leaning
  p.softShadow(10, 17, 9, 2, 0.4);
  p.line(3, 16, 5, 6, P.cloud); p.line(5, 6, 9, 2, P.cloud); p.line(9, 2, 13, 3, P.cloud);
  p.line(4, 16, 6, 7, P.white); p.line(6, 7, 9, 3, lighten(P.cloud, 0.1));
  p.line(6, 16, 8, 7, mix(P.cloud, P.sky, 0.25)); p.line(8, 7, 11, 4, mix(P.cloud, P.sky, 0.25));
  p.line(13, 3, 15, 5, darken(P.cloud, 0.12)); p.px(13, 3, P.white);      // snapped stub, jagged break
  p.px(9, 2, P.gold); p.px(7, 5, withAlpha(P.holy, 0.5)); p.px(11, 3, withAlpha(P.holy, 0.4));
  p.glow(9, 4, 2.4, P.holy, 0.22, 2);
  p.star4(9, 2, 1.6, P.holyL, P.white);
  p.rimLight(P.rim, 0.4);
  p.outline(P.ink);
}, { anchor: 'feet' });

// ---------------------------------------------------------------------------------------------
